from collections import defaultdict
import datetime

class LogAggregator:
    def __init__(self):
        self._logs = []

    def add_log(self, log_entry):
        self._logs.append(log_entry)

    def get_logs(self):
        return list(self._logs)

    def aggregate_by_level(self):
        level_counts = defaultdict(int)
        for log in self._logs:
            level = log.get('level', 'UNKNOWN')
            level_counts[level] += 1
        return dict(level_counts)

    def aggregate_by_source(self):
        source_counts = defaultdict(int)
        for log in self._logs:
            source = log.get('source', 'UNKNOWN')
            source_counts[source] += 1
        return dict(source_counts)

    def filter_by_level(self, level_to_filter):
        return [log for log in self._logs if log.get('level') == level_to_filter]

    def filter_by_time_range(self, start_time_iso, end_time_iso):
        filtered_logs = []
        try:
            start_dt = datetime.datetime.fromisoformat(start_time_iso.replace('Z', '+00:00'))
            end_dt = datetime.datetime.fromisoformat(end_time_iso.replace('Z', '+00:00'))
        except ValueError:
            return []

        for log in self._logs:
            log_timestamp_str = log.get('timestamp')
            if log_timestamp_str:
                try:
                    log_dt = datetime.datetime.fromisoformat(log_timestamp_str.replace('Z', '+00:00'))
                    if start_dt <= log_dt <= end_dt:
                        filtered_logs.append(log)
                except ValueError:
                    pass
        return filtered_logs

    def clear_logs(self):
        self._logs = []
